let pdfLocation = $json.body.pdfLocation || '';

// If Google Drive link, convert to direct download URL
if (pdfLocation.includes('drive.google.com')) {
  let fileId = '';
  const fileDMatch = pdfLocation.match(/\/file\/d\/([a-zA-Z0-9_-]+)/);
  if (fileDMatch && fileDMatch[1]) {
    fileId = fileDMatch[1];
  } else {
    const idParamMatch = pdfLocation.match(/[?&]id=([a-zA-Z0-9_-]+)/);
    if (idParamMatch && idParamMatch[1]) {
      fileId = idParamMatch[1];
    }
  }

  if (fileId) {
    pdfLocation = `https://drive.google.com/uc?export=download&id=${fileId}`;
  }
}

return {
  pdfLocation
};

